```javascript
const cors = require('cors');
const helmet = require('helmet');

// Use helmet for security headers
app.use(helmet());

// Configure CORS properly
app.use(cors({
  origin: ['https://trusted-domain.com'], // Whitelist specific origins
  credentials: true,
  methods: ['GET', 'POST'],
  allowedHeaders: ['Content-Type']
}));
```

