#### **4. No CORS Protection (OWASP A01:2021 - Broken Access Control)**
**Risk Level:** MEDIUM
**Issue:** CORS headers are not configured, potentially allowing unauthorized cross-origin requests.

**Recommendation:**
```javascript
const cors = require('cors');

// Strict CORS configuration
const corsOptions = {
  origin: process.env.ALLOWED_ORIGINS?.split(',') || ['https://example.com'],
  credentials: true,
  optionsSuccessStatus: 200,
  methods: ['GET', 'POST', 'PUT', 'DELETE'],
  allowedHeaders: ['Content-Type', 'Authorization'],
  maxAge: 86400, // 24 hours
};

app.use(cors(corsOptions));

// Alternative: Manual CORS headers
app.use((req, res, next) => {
  res.header('Access-Control-Allow-Origin', process.env.ALLOWED_ORIGIN);
  res.header('Access-Control-Allow-Credentials', 'true');
  res.header('Access-Control-Allow-Methods', 'GET, POST');
  res.header('Access-Control-Allow-Headers', 'Content-Type, Authorization');
  next();
});
```

---

#### **5. Missing Security Headers (OWASP A05:2021 - Security Misconfiguration)**
**Risk Level:** HIGH
**Issue:** No Content Security Policy, X-Frame-Options, or other protective headers.

**Recommendation:**
```javascript
const helmet = require('helmet');

// Use helmet to set security headers
app.use(helmet());

// Manual configuration for additional control:
app.use((req, res, next) => {
  res.setHeader('X-Content-Type-Options', 'nosniff');
  res.setHeader('X-Frame-Options', 'DENY');
  res.setHeader('X-XSS-Protection', '1; mode=block');
  res.setHeader('Strict-Transport-Security', 'max-age=31536000; includeSubDomains');
  res.setHeader('Content-Security-Policy', "default-src 'self'");
  res.setHeader('Referrer-Policy', 'strict-origin-when-cross-origin');
  next();
});
```

