#### **8. No Logging/Monitoring (OWASP A09:2021 - Logging and Monitoring Failures)**
**Risk Level:** MEDIUM
**Issue:** No security event logging for auditing suspicious activity.

**Recommendation:**
```javascript
const morgan = require('morgan');

// Log all requests
app.use(morgan('combined'));

// Custom security logging
app.use((req, res, next) => {
  const originalSend = res.send;
  res.send = function(data) {
    // Log unauthorized attempts
    if (res.statusCode === 401 || res.statusCode === 403) {
      console.error(`[SECURITY] ${res.statusCode} from ${req.ip} to ${req.path}`);
    }
    originalSend.call(this, data);
  };
  next();
});
```

